/**
 * @brief 零开销二分查找（时间复杂度：O(log N)）
 * @param key Shape Key字符串（必须与搜索器输出格式完全一致）
 * @return 找到返回记录指针，否则返回nullptr
 * @note 平均查询时间：< 10ns
 */
inline const ExperienceRecord* lookup(std::string_view key) {
    auto it = std::lower_bound(
        TABLE.begin(), TABLE.end(), key,
        [](const ExperienceRecord& rec, std::string_view k) {
            return std::string_view(rec.shape_key) < k;
        });
    
    if (it != TABLE.end() && std::string_view(it->shape_key) == key) {
        return &(*it);
    }
    return nullptr;
}

/**
 * @brief 统计信息
 */
inline void print_statistics() {
    std::cout << "[Experience Table Statistics]" << std::endl;
    std::cout << "  Total records: " << TABLE.size() << std::endl;
    
    // 统计各操作类型数量
    int fprop_count = 0, genstats_count = 0, dgrad_count = 0, wgrad_count = 0;
    for (const auto& rec : TABLE) {
        std::string_view key(rec.shape_key);
        if (key.find("conv_fprop") != std::string_view::npos) ++fprop_count;
        else if (key.find("conv_genstats") != std::string_view::npos) ++genstats_count;
        else if (key.find("conv_dgrad") != std::string_view::npos) ++dgrad_count;
        else if (key.find("conv_wgrad") != std::string_view::npos) ++wgrad_count;
    }
    
    std::cout << "  By operation type:" << std::endl;
    std::cout << "    Conv Fprop:    " << fprop_count << std::endl;
    std::cout << "    Conv GenStats: " << genstats_count << std::endl;
    std::cout << "    Conv DGrad:    " << dgrad_count << std::endl;
    std::cout << "    Conv WGrad:   " << wgrad_count << std::endl;
    
    // 统计来源分布
    int exhaustive_count = 0, heur_a_count = 0, heur_b_count = 0;
    for (const auto& rec : TABLE) {
        std::string_view src(rec.source);
        if (src == "exhaustive") ++exhaustive_count;
        else if (src == "heur_a") ++heur_a_count;
        else if (src == "heur_b") ++heur_b_count;
    }
    
    std::cout << "  By source:" << std::endl;
    std::cout << "    Exhaustive:    " << exhaustive_count << std::endl;
    std::cout << "    Heuristic A:   " << heur_a_count << std::endl;
    std::cout << "    Heuristic B:   " << heur_b_count << std::endl;
}

